content:
{
  "sentences": [
    {
      "text": "這件上衣的顏色太紅了。",
      "pinyin": "Zhè jiàn shàngyī de yánsè tài hóng le.",
      "pinyin_numeric": "zhe4 jian4 shang4yi1 de5 yan2se4 tai4 hong2 le5",
      "translation_en": "The color of this top is too red.",
      "translation_ko": "이 상의의 색깔이 너무 빨개요."
    },
    {
      "text": "這條褲子的尺寸太大了。",
      "pinyin": "Zhè tiáo kùzi de chǐcùn tài dà le.",
      "pinyin_numeric": "zhe4 tiao2 ku4zi5 de5 chi3cun4 tai4 da4 le5",
      "translation_en": "The size of these pants is too big.",
      "translation_ko": "이 바지의 사이즈가 너무 커요."
    },
    {
      "text": "這雙鞋子太貴了，可以便宜一點嗎？",
      "pinyin": "Zhè shuāng xiézi tài guì le, kěyǐ piányí yīdiǎn ma?",
      "pinyin_numeric": "zhe4 shuang1 xie2zi5 tai4 gui4 le5, ke3yi3 pian2yi2 yi1dian3 ma0",
      "translation_en": "These shoes are too expensive. Can you make it a little cheaper?",
      "translation_ko": "이 신발이 너무 비싸요. 조금 깎아 주실 수 있나요?"
    },
    {
      "text": "這件外套的顏色太黑了，有沒有白色的？",
      "pinyin": "Zhè jiàn wàitào de yánsè tài hēi le, yǒu méiyǒu báisè de?",
      "pinyin_numeric": "zhe4 jian4 wai4tao4 de5 yan2se4 tai4 hei1 le5, you3 mei2you3 bai2se4 de5",
      "translation_en": "The color of this jacket is too black. Do you have a white one?",
      "translation_ko": "이 재킷의 색깔이 너무 검어요. 흰색이 있나요?"
    },
    {
      "text": "這件裙子太短了，我想試穿長一點的。",
      "pinyin": "Zhè jiàn qúnzi tài duǎn le, wǒ xiǎng shìchuān cháng yīdiǎn de.",
      "pinyin_numeric": "zhe4 jian4 qun2zi5 tai4 duan3 le5, wo3 xiang3 shi4chuan1 chang2 yi1dian3 de5",
      "translation_en": "This skirt is too short. I want to try on a longer one.",
      "translation_ko": "이 치마가 너무 짧아요. 더 긴 것을 입어 보고 싶어요."
    },
    {
      "text": "這件上衣的尺寸太小了，可以換大號嗎？",
      "pinyin": "Zhè jiàn shàngyī de chǐcùn tài xiǎo le, kěyǐ huàn dàhào ma?",
      "pinyin_numeric": "zhe4 jian4 shang4yi1 de5 chi3cun4 tai4 xiao3 le5, ke3yi3 huan4 da4hao4 ma0",
      "translation_en": "The size of this top is too small. Can I exchange it for a large?",
      "translation_ko": "이 상의의 사이즈가 너무 작아요. 라지로 교환할 수 있나요?"
    },
    {
      "text": "這條褲子的顏色太藍了，我不喜歡。",
      "pinyin": "Zhè tiáo kùzi de yánsè tài lán le, wǒ bù xǐhuān.",
      "pinyin_numeric": "zhe4 tiao2 ku4zi5 de5 yan2se4 tai4 lan2 le5, wo3 bu4 xi3huan1",
      "translation_en": "The color of these pants is too blue. I don't like it.",
      "translation_ko": "이 바지의 색깔이 너무 파래요. 마음에 안 들어요."
    },
    {
      "text": "這雙鞋子太厚了，有沒有薄一點的？",
      "pinyin": "Zhè shuāng xiézi tài hòu le, yǒu méiyǒu báo yīdiǎn de?",
      "pinyin_numeric": "zhe4 shuang1 xie2zi5 tai4 hou4 le5, you3 mei2you3 bao2 yi1dian3 de5",
      "translation_en": "These shoes are too thick. Do you have a thinner pair?",
      "translation_ko": "이 신발이 너무 두꺼워요. 더 얇은 게 있나요?"
    },
    {
      "text": "這件外套太薄了，冬天穿會很冷。",
      "pinyin": "Zhè jiàn wàitào tài báo le, dōngtiān chuān huì hěn lěng.",
      "pinyin_numeric": "zhe4 jian4 wai4tao4 tai4 bao2 le5, dong1tian1 chuan1 hui4 hen3 leng3",
      "translation_en": "This jacket is too thin. Wearing it in winter will be very cold.",
      "translation_ko": "이 재킷이 너무 얇아요. 겨울에 입으면 매우 추울 거예요."
    },
    {
      "text": "這件裙子的尺寸剛好，可是顏色太黃了。",
      "pinyin": "Zhè jiàn qúnzi de chǐcùn gānghǎo, kěshì yánsè tài huáng le.",
      "pinyin_numeric": "zhe4 jian4 qun2zi5 de5 chi3cun4 gang1hao3, ke3shi4 yan2se4 tai4 huang2 le5",
      "translation_en": "The size of this skirt is just right, but the color is too yellow.",
      "translation_ko": "이 치마의 사이즈는 딱 맞는데 색깔이 너무 노래요."
    }
  ]
}
